// NewServer creates a new gRPC server with reflection enabled
func NewServer(port int) (*Server, error) {
	lis, err := net.Listen("tcp", fmt.Sprintf(":%d", port))
	if err != nil {
		return nil, fmt.Errorf("failed to listen on port %d: %w", port, err)
	}

	// Create gRPC server with interceptors for logging
	grpcServer := grpc.NewServer(
		grpc.UnaryInterceptor(loggingUnaryInterceptor),
		grpc.StreamInterceptor(loggingStreamInterceptor),
	)

	// Register reflection service for all environments (dev, staging, production)
	// This enables clients to discover services and methods dynamically
	// Useful for:
	// - grpcurl and grpc_cli tools
	// - Dynamic service discovery in microservices architecture
	// - Debugging and testing in all environments
	// - API documentation generation
	reflection.Register(grpcServer)
	log.Println("gRPC reflection API enabled - clients can discover services and methods dynamically")

	server := &Server{
		grpcServer: grpcServer,
		listener:   lis,
		services:   make([]ServiceInfo, 0),
	}

	// Register example services
	server.registerServices()

	return server, nil
}

