// Start begins serving gRPC requests
func (s *Server) Start() error {
	log.Printf("gRPC server starting on %s", s.listener.Addr().String())
	log.Println("Reflection is enabled - use grpcurl or grpc_cli to discover services:")
	log.Printf("  grpcurl -plaintext localhost:%d list", s.listener.Addr().(*net.TCPAddr).Port)
	log.Printf("  grpcurl -plaintext localhost:%d describe", s.listener.Addr().(*net.TCPAddr).Port)
	return s.grpcServer.Serve(s.listener)
}

// Stop gracefully stops the gRPC server
func (s *Server) Stop() {
	log.Println("Gracefully stopping gRPC server...")
	s.grpcServer.GracefulStop()
	log.Println("gRPC server stopped")
}

// Logging interceptor for unary RPCs
func loggingUnaryInterceptor(
	ctx context.Context,
	req interface{},
	info *grpc.UnaryServerInfo,
	handler grpc.UnaryHandler,
) (interface{}, error) {
	log.Printf("Unary RPC: %s", info.FullMethod)
	resp, err := handler(ctx, req)
	if err != nil {
		log.Printf("Unary RPC %s failed: %v", info.FullMethod, err)
	} else {
		log.Printf("Unary RPC %s completed successfully", info.FullMethod)
	}
	return resp, err
}

// Logging interceptor for streaming RPCs
func loggingStreamInterceptor(
	srv interface{},
	ss grpc.ServerStream,
	info *grpc.StreamServerInfo,
	handler grpc.StreamHandler,
) error {
	log.Printf("Stream RPC: %s (client_stream=%v, server_stream=%v)",
		info.FullMethod, info.IsClientStream, info.IsServerStream)
	err := handler(srv, ss)
	if err != nil {
		log.Printf("Stream RPC %s failed: %v", info.FullMethod, err)
	} else {
		log.Printf("Stream RPC %s completed successfully", info.FullMethod)
	}
	return err
}

