// Greeter service

type HelloRequest struct {
	Name string
}

type HelloReply struct {
	Message string
}

type GreeterServer interface {
	SayHello(context.Context, *HelloRequest) (*HelloReply, error)
}

type GreeterServiceImpl struct{}

func (s *GreeterServiceImpl) SayHello(ctx context.Context, req *HelloRequest) (*HelloReply, error) {
	if req.Name == "" {
		return nil, status.Error(codes.InvalidArgument, "name is required")
	}
	return &HelloReply{
		Message: fmt.Sprintf("Hello, %s! Welcome to our microservices architecture.", req.Name),
	}, nil
}

// RegisterGreeterServer registers the Greeter service with the gRPC server
// In a real project, this would be auto-generated from protobuf definitions
func RegisterGreeterServer(s *grpc.Server, srv GreeterServer) {
	// Create a proper service description
	sd := grpc.ServiceDesc{
		ServiceName: "greeter.Greeter",
		HandlerType: (*GreeterServer)(nil),
		Methods: []grpc.MethodDesc{
			{
				MethodName: "SayHello",
				Handler: func(srv interface{}, ctx context.Context, dec func(interface{}) error, interceptor grpc.UnaryServerInterceptor) (interface{}, error) {
					in := new(HelloRequest)
					if err := dec(in); err != nil {
						return nil, err
					}
					if interceptor == nil {
						return srv.(GreeterServer).SayHello(ctx, in)
					}
					info := &grpc.UnaryServerInfo{
						Server:     srv,
						FullMethod: "/greeter.Greeter/SayHello",
					}
					handler := func(ctx context.Context, req interface{}) (interface{}, error) {
						return srv.(GreeterServer).SayHello(ctx, req.(*HelloRequest))
					}
					return interceptor(ctx, in, info, handler)
				},
			},
		},
		Streams:  []grpc.StreamDesc{},
		Metadata: "greeter.proto",
	}
	s.RegisterService(&sd, srv)
}

